angular.module("Songs").controller("ImportCtrl",function($scope,$http,$timeout){$scope.tab="songs";$scope.msgLang="ru";$scope.selectedMsgFile=null;$scope.msgImporting=false;$scope.msgProgress=0;$scope.msgLog=[];$scope.msgSubTab="sog";$scope.txtCode="";$scope.txtTitle="";$scope.txtCity="";$scope.txtBody="";$scope.txtParaSep="emptyline";$scope.txtAudioSrc="";$scope.txtTimecodes="";$scope.txtImporting=false;$scope.txtEditLoading=false;$scope.countTimecodes=function(){if(!$scope.txtTimecodes)return 0;return $scope.txtTimecodes.split("\n").filter(function(l){return l.trim()!==""}).length};$scope.countParagraphs=function(){if(!$scope.txtBody)return 0;if($scope.txtParaSep==="emptyline"){return $scope.txtBody.split(/\n{2,}/).filter(function(b){return b.trim()!==""}).length}return $scope.txtBody.split("\n").filter(function(l){return l.trim()!==""}).length};$scope.songLists=[];$scope.songListId="";$scope.songLang="ru";$scope.newListName="";$scope.creating=false;$scope.selectedSogFile=null;$scope.selectedZipFile=null;$scope.songImporting=false;$scope.zipImporting=false;$scope.songProgress=0;$scope.zipProgress=0;$scope.songLog=[];$scope.msgLang="ru";$scope.selectedMsgFile=null;$scope.msgImporting=false;$scope.msgProgress=0;$scope.msgLog=[];$scope.txtMode="new";$scope.txtCodeSuggestions=[];$scope.txtCodeSearching=false;$scope.langList=[];$scope.langLoading=false;$scope.newLangCode="";$scope.newLangLabel="";$scope.langAdding=false;$scope.langDeleteTarget=null;$scope.langDeletePassword="";$scope.langDeleting=false;$scope.langLog=[];$scope.loadLanguages=function(){$scope.langLoading=true;$http({method:"POST",url:"/ajax",data:{command:"get_languages"}}).then(function(r){$scope.langLoading=false;var list=r.data||[];$scope.langList=list;if(list.length===0)return;var defaultLang=null;for(var i=0;i<list.length;i++){if(list[i].is_default=="1"){defaultLang=list[i].code;break}}if(!defaultLang)defaultLang=list[0].code;var validCodes={};for(var j=0;j<list.length;j++)validCodes[list[j].code]=true;if(!validCodes[$scope.songLang])$scope.songLang=defaultLang;if(!validCodes[$scope.msgLang])$scope.msgLang=defaultLang},function(){$scope.langLoading=false;console.error("Не удалось загрузить список языков")})};$scope.addLanguage=function(){var code=($scope.newLangCode||"").toLowerCase().trim();var label=($scope.newLangLabel||"").toUpperCase().trim();if(!code||!label)return;if(!/^[a-z]{2,5}$/.test(code)){langLog("error",'❌ Код должен быть 2–5 латинских букв (напр. "de")');return}$scope.langAdding=true;$scope.langLog=[];$http({method:"POST",url:"/ajax",data:{command:"add_language",code:code,label:label}}).then(function(r){$scope.langAdding=false;var d=r.data;if(d.status==="success"){langLog("ok","✅ "+d.message);$scope.newLangCode="";$scope.newLangLabel="";$scope.loadLanguages()}else{langLog("error","❌ "+(d.message||"Ошибка сервера"))}},function(){$scope.langAdding=false;langLog("error","❌ Ошибка соединения")})};$scope.toggleDeletePanel=function(lang){if($scope.langDeleteTarget===lang.code){$scope.langDeleteTarget=null;$scope.langDeletePassword=""}else{$scope.langDeleteTarget=lang.code;$scope.langDeletePassword=""}};$scope.deleteLanguage=function(lang){if(!$scope.langDeletePassword)return;$scope.langDeleting=true;$scope.langLog=[];$http({method:"POST",url:"/ajax",data:{command:"delete_language",code:lang.code,delete_password:$scope.langDeletePassword}}).then(function(r){$scope.langDeleting=false;$scope.langDeletePassword="";$scope.langDeleteTarget=null;var d=r.data;if(d.status==="success"){langLog("ok","✅ "+d.message);$scope.loadLanguages()}else{langLog("error","❌ "+(d.message||"Неверный пароль или ошибка сервера"))}},function(){$scope.langDeleting=false;langLog("error","❌ Ошибка соединения")})};function langLog(type,msg){$scope.langLog.push({type:type,msg:msg});$timeout(function(){var el=document.getElementById("langLogEl");if(el)el.scrollTop=el.scrollHeight},50)}function loadSongLists(){$http({method:"POST",url:"/ajax",data:{command:"get_all_song_lists"}}).then(function(r){$scope.songLists=r.data||[]})}loadSongLists();$scope.loadLanguages();$scope.createSongList=function(){if(!$scope.newListName)return;$scope.creating=true;$http({method:"POST",url:"/ajax",data:{command:"create_song_list",name:$scope.newListName}}).then(function(r){$scope.creating=false;if(r.data&&r.data.status==="success"){$scope.newListName="";loadSongLists();$scope.songListId=r.data.list_id;songLog("ok","Сборник создан, ID="+r.data.list_id)}else{songLog("error","Ошибка: "+(r.data&&r.data.message?r.data.message:"неизвестная"))}},function(){$scope.creating=false;songLog("error","Ошибка соединения")})};$scope.onSongSogSelected=function(){var f=document.getElementById("songSogFile");$scope.$apply(function(){$scope.selectedSogFile=f&&f.files[0]?f.files[0]:null})};$scope.onSongZipSelected=function(){var f=document.getElementById("songZipFile");$scope.$apply(function(){$scope.selectedZipFile=f&&f.files[0]?f.files[0]:null})};$scope.onMsgSogSelected=function(){var f=document.getElementById("msgSogFile");$scope.$apply(function(){$scope.selectedMsgFile=f&&f.files[0]?f.files[0]:null})};function songLog(type,msg){$scope.songLog.push({type:type,msg:msg});$timeout(function(){var el=document.getElementById("songLogEl");if(el)el.scrollTop=el.scrollHeight},50)}function msgLog(type,msg){$scope.msgLog.push({type:type,msg:msg});$timeout(function(){var el=document.getElementById("msgLogEl");if(el)el.scrollTop=el.scrollHeight},50)}$scope.importSongsSog=function(){if(!$scope.selectedSogFile||!$scope.songListId)return;$scope.songImporting=true;$scope.songProgress=0;$scope.songLog=[];songLog("ok","Начинаем импорт текстов…");var fd=new FormData;fd.append("command","import_songs_sog");fd.append("list_id",$scope.songListId);fd.append("lang",$scope.songLang);fd.append("sogfile",$scope.selectedSogFile);$http.post("/ajax",fd,{transformRequest:angular.identity,headers:{"Content-Type":undefined}}).then(function(r){$scope.songImporting=false;$scope.songProgress=100;var d=r.data;if(d.status==="success"){songLog("ok","✅ Импорт завершён. Добавлено/обновлено: "+d.updated+", ошибок: "+d.errors);if(d.log&&d.log.length){angular.forEach(d.log,function(l){songLog(l.type,l.msg)})}}else{songLog("error","❌ "+(d.message||"Ошибка сервера"))}},function(){$scope.songImporting=false;songLog("error","❌ Ошибка соединения")})};$scope.importSongZip=function(){if(!$scope.selectedZipFile||!$scope.songListId)return;$scope.zipImporting=true;$scope.zipProgress=0;$scope.songLog=[];songLog("ok","Загружаем ZIP-архив…");var fd=new FormData;fd.append("command","import_song_images_zip");fd.append("list_id",$scope.songListId);fd.append("zipfile",$scope.selectedZipFile);$http.post("/ajax",fd,{transformRequest:angular.identity,headers:{"Content-Type":undefined}}).then(function(r){$scope.zipImporting=false;$scope.zipProgress=100;var d=r.data;if(d.status==="success"){songLog("ok","✅ Картинки импортированы. Извлечено: "+d.extracted+", ошибок: "+d.errors);if(d.log&&d.log.length){angular.forEach(d.log,function(l){songLog(l.type,l.msg)})}}else{songLog("error","❌ "+(d.message||"Ошибка сервера"))}},function(){$scope.zipImporting=false;songLog("error","❌ Ошибка соединения")})};$scope.importMessagesSog=function(){if(!$scope.selectedMsgFile)return;$scope.msgImporting=true;$scope.msgProgress=0;$scope.msgLog=[];msgLog("ok","Начинаем импорт посланий…");var fd=new FormData;fd.append("command","import_messages_sog");fd.append("lang",$scope.msgLang);fd.append("sogfile",$scope.selectedMsgFile);$http.post("/ajax",fd,{transformRequest:angular.identity,headers:{"Content-Type":undefined}}).then(function(r){$scope.msgImporting=false;$scope.msgProgress=100;var d=r.data;if(d.status==="success"){msgLog("ok","✅ Импорт завершён. Добавлено: "+d.inserted+", обновлено: "+d.updated+", ошибок: "+d.errors);if(d.log&&d.log.length){angular.forEach(d.log,function(l){msgLog(l.type,l.msg)})}}else{msgLog("error","❌ "+(d.message||"Ошибка сервера"))}},function(){$scope.msgImporting=false;msgLog("error","❌ Ошибка соединения")})};$scope.importMessagesText=function(){if(!$scope.txtCode||!$scope.txtBody)return;if($scope.txtMode==="new"&&!$scope.txtTitle)return;$scope.txtImporting=true;$scope.msgLog=[];msgLog("ok","Сохраняем послание ["+$scope.txtCode+"]…");$http({method:"POST",url:"/ajax",data:{command:"import_messages_text",lang:$scope.msgLang,code:$scope.txtCode.trim(),title:$scope.txtTitle.trim(),city:$scope.txtCity.trim(),para_sep:$scope.txtParaSep,body:$scope.txtBody,mode:$scope.txtMode,audio_src:$scope.txtAudioSrc.trim(),timecodes:$scope.txtTimecodes}}).then(function(r){$scope.txtImporting=false;var d=r.data;if(d.status==="success"){msgLog("ok","✅ "+d.message);if(d.warning){msgLog("warn",d.warning)}if(d.action==="inserted"){$scope.txtCode="";$scope.txtTitle="";$scope.txtCity="";$scope.txtBody="";$scope.txtAudioSrc="";$scope.txtTimecodes=""}}else{msgLog("error","❌ "+(d.message||"Ошибка сервера"))}},function(){$scope.txtImporting=false;msgLog("error","❌ Ошибка соединения")})};var codeSearchTimer=null;$scope.onTxtCodeInput=function(){if($scope.txtMode!=="translate"&&$scope.txtMode!=="edit"||$scope.txtCode.length<2){$scope.txtCodeSuggestions=[];return}if(codeSearchTimer)$timeout.cancel(codeSearchTimer);codeSearchTimer=$timeout(function(){$scope.txtCodeSearching=true;$http({method:"POST",url:"/ajax",data:{command:"search_messages_by_code",query:$scope.txtCode}}).then(function(r){$scope.txtCodeSearching=false;$scope.txtCodeSuggestions=r.data||[]},function(){$scope.txtCodeSearching=false})},300)};$scope.loadMessageForEdit=function(code){$scope.txtEditLoading=true;$http({method:"POST",url:"/ajax",data:{command:"load_message_for_edit",code:code}}).then(function(r){$scope.txtEditLoading=false;var d=r.data;if(!d){msgLog("error","❌ Послание не найдено: "+code);return}var langToField={ru:"TEXT",lt:"TEXT_LT",en:"TEXT_EN",de:"TEXT_DE"};var field=langToField[$scope.msgLang]||"TEXT";var text=(d[field]||"").replace(/\r\n/g,"\n").replace(/\r/g,"\n");$scope.txtTitle=d.TITLE||"";$scope.txtCity=d.CITY||"";$scope.txtBody=text.replace(/\n/g,"\n\n");$scope.txtParaSep="emptyline";$scope.txtAudioSrc=d.AUDIO_SRC||"";$scope.txtTimecodes=(d.TIMECODES||"").replace(/\r\n/g,"\n").replace(/\r/g,"\n")},function(){$scope.txtEditLoading=false;msgLog("error","❌ Ошибка загрузки данных")})};$scope.selectCodeSuggestion=function(msg){$scope.txtCode=msg.CODE;$scope.txtCodeSuggestions=[];if($scope.txtMode==="edit"){$scope.loadMessageForEdit(msg.CODE)}};$scope.clearCodeSuggestions=function(){$timeout(function(){$scope.txtCodeSuggestions=[]},200)};$scope.$watch("txtMode",function(newVal,oldVal){if(newVal===oldVal)return;$scope.txtTitle="";$scope.txtCity="";$scope.txtBody="";$scope.txtAudioSrc="";$scope.txtTimecodes="";$scope.txtCodeSuggestions=[]})});